        display: table;
    }

    .bemmae-travel-table thead {
        background-color: #d81b60;
        color: #fff;
    }

    .bemmae-travel-table th {
        padding: 15px;
        text-align: left;
        font-size: 14px;
        text-transform: uppercase;
    }

    .bemmae-travel-table td {
        padding: 15px;
        border-bottom: 1px solid #eee;
        color: #444;
        font-size: 14px;
        line-height: 1.5;
    }

    .comp-name {
        font-weight: 800;
        color: #d81b60;
        font-size: 16px;
    }

    /* Transformação para Mobile */
    @media (max-width: 768px) {
        .bemmae-travel-table, 
        .bemmae-travel-table thead, 
        .bemmae-travel-table tbody, 
        .bemmae-travel-table th, 
        .bemmae-travel-table td, 
        .bemmae-travel-table tr { 
            display: block; 
        }

        .bemmae-travel-table thead tr {
            position: absolute;
            top: -9999px;
            left: -9999px;
        }

        .bemmae-travel-table tr {
            border: 1px solid #eee;
            margin-bottom: 15px;
            border-radius: 12px;
            padding: 10px;
            background: #fff;
        }

        .bemmae-travel-table td {
            border: none;
            position: relative;
            padding-left: 45% !important;
            text-align: left !important;
            min-height: 30px;
        }

        .bemmae-travel-table td:before {
            content: attr(data-label);
            position: absolute;
            left: 15px;
            width: 40%;
            font-weight: 700;
            color: #d81b60;
            font-size: 12px;
            text-transform: uppercase;
        }

        .bemmae-travel-table td.comp-cell {
            padding-left: 15px !important;
            background: #fdf2f5;
            border-radius: 8px;
            margin-bottom: 10px;
        }

        .bemmae-travel-table td.comp-cell:before {
            display: none;
        }

        .comp-name {
            font-size: 18px;
        }
    }
</style>

