            <li>Fácil de fechar com uma mão</li>
            <li>Tecido lavável e acolchoado</li>
        </ul>
        <a href="SEU-LINK-AFILIADO-AQUI" class="product-cta" target="_blank" rel="nofollow">Ver Preço na Amazon</a>
    </div>
</div>","visibility":{"web":{"nonMember":true,"memberSegment":"status:free,status:-free"},"email":{"memberSegment":"status:free,status:-free"}}}]}

